"import asyncio\nfrom sqlalchemy import text\nfrom app.database import async_session\n\nasync def run():\n    try:\n        async with async_session() as session:\n            res = await session.execute(text(\"SELECT rolname, rolsuper, rolbypassrls FROM pg_roles WHERE rolname = current_user\"))\n            row = res.fetchone()\n            res_text = f\"User: {row[0]}, Superuser: {row[1]}, BypassRLS: {row[2]}\"\n            with open('scripts/role_info.txt', 'w') as f:\n                f.write(res_text)\n            print(res_text)\n    except Exception as e:\n        with open('scripts/role_info.txt', 'w') as f:\n            f.write(f\"Error: {e}\")\n\nif __name__ == '__main__':\n    asyncio.run(run())\n"
